import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import com.google.gson.JsonElement;
import com.google.gson.JsonObject;
import com.google.gson.internal.bind.JsonTreeWriter;
import com.google.gson.JsonNull;
import com.google.gson.stream.JsonWriter;
import java.io.IOException;
import java.lang.reflect.Field;
import java.util.List;
import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;

class JsonTreeWriterTest {
  private JsonTreeWriter jsonTreeWriter;

  @BeforeEach
  void setUp() {
    jsonTreeWriter = new JsonTreeWriter();
  }

  @Test
  void beginObject_shouldAddJsonObjectToStackAndReturnThis() throws IOException, NoSuchFieldException, IllegalAccessException {
    JsonWriter returned = jsonTreeWriter.beginObject();
    assertSame(jsonTreeWriter, returned);

    Field stackField = JsonTreeWriter.class.getDeclaredField("stack");
    stackField.setAccessible(true);
    @SuppressWarnings("unchecked")
    List<JsonElement> stack = (List<JsonElement>) stackField.get(jsonTreeWriter);

    assertFalse(stack.isEmpty());
    JsonElement top = stack.get(stack.size() - 1);
    assertTrue(top instanceof JsonObject);

    // Verify that the top of the stack is the same object passed to put()
    Field productField = JsonTreeWriter.class.getDeclaredField("product");
    productField.setAccessible(true);
    JsonElement product = (JsonElement) productField.get(jsonTreeWriter);

    assertNotNull(product);
    assertTrue(product instanceof JsonNull || product instanceof JsonObject);
  }
}
